const failed = $input.all();
if (failed.length === 0) return [];

// Bygg feilanalyse-prompt
const videoList = failed.map(v => ({
  id: v.json.id,
  topic: v.json.topic,
  sub_status: v.json.sub_status,
  created_at: v.json.created_at
}));

const prompt = `Analyze these failed video productions and determine the likely cause of failure:\n\n${JSON.stringify(videoList, null, 2)}\n\nFor each failed video, respond with JSON array containing:\n- video_id: string\n- error_type: string (one of: network_error, api_rate_limit, script_parsing_error, media_not_found, voiceover_failed, ffmpeg_error, supabase_error, auth_error, timeout_error, unknown)\n- likely_cause: string (brief explanation)\n- fix_recommendation: string (what to fix for retry)\n\nReturn only valid JSON array.`;

return [{ json: { prompt, videos: videoList, count: failed.length } }];

