parameters.jsCode:
const response = $input.first().json.choices[0].message.content;
let analysis = [];
try { analysis = JSON.parse(response); }
catch { try { const match = response.match(/\[[\s\S]*\]/); if (match) analysis = JSON.parse(match[0]); } catch(e) { analysis = []; } }

if (!Array.isArray(analysis) || analysis.length === 0) {
  return [{ json: { action: 'none', message: 'No errors to fix' } }];
}

// Bygg oppdateringer basert på analyse
const updates = analysis.map(a => ({
  video_id: a.video_id,
  error_type: a.error_type,
  likely_cause: a.likely_cause,
  fix_recommendation: a.fix_recommendation,
  // Reset til queued for retry
  status: 'queued',
  progress: 0,
  sub_status: 'Auto-retry etter feilretting: ' + (a.likely_cause || 'unknown')
}));

return updates.map(u => ({ json: u }));
